import { Injectable } from '@angular/core';
import { BehaviorSubject } from 'rxjs';
import { StockItem } from '../models/stock-item';
import { StockStorageService } from './stock-storage.service';

@Injectable({
  providedIn: 'root'
})
export class StockStoreService {
  private readonly itemsSubject = new BehaviorSubject<StockItem[]>([]);
  readonly items$ = this.itemsSubject.asObservable();

  private loaded = false;

  constructor(private storage: StockStorageService) {}

  async load(): Promise<void> {
    if (this.loaded) return;
    await this.storage.ensureSeed();
    await this.refresh();
    this.loaded = true;
  }

  async refresh(): Promise<void> {
    const all = await this.storage.getAll();
    const sorted = [...all].sort((a, b) => {
      const cat = a.category.localeCompare(b.category);
      if (cat !== 0) return cat;
      return a.reference.localeCompare(b.reference);
    });
    this.itemsSubject.next(sorted);
  }

  getSnapshot(): StockItem[] {
    return this.itemsSubject.value;
  }

  async setQuantity(id: string, quantity: number): Promise<void> {
    const all = this.itemsSubject.value;
    const next = all.map((item) => {
      if (item.id !== id) return item;
      return {
        ...item,
        quantity,
        lastUpdated: new Date().toISOString()
      };
    });

    await this.storage.saveAll(next);
    this.itemsSubject.next(next);
  }
}
